define([],function(){"use strict";var waitForExtension=function(t){return new Promise(function(r){var s=Date.now(),p=function(){window.nostr?r(window.nostr):Date.now()-s<t?setTimeout(p,100):r(null)};p()})};var fetchKind0=function(r,p,t){return new Promise(function(res){var timer=setTimeout(function(){res(null)},t);try{var ws=new WebSocket(r);ws.onopen=function(){ws.send(JSON.stringify(["REQ","auth-meta",{kinds:[0],authors:[p],limit:1}]))};ws.onmessage=function(e){try{var m=JSON.parse(e.data);if(m[0]==="EVENT"&&m[2]&&m[2].kind===0){clearTimeout(timer);ws.close();res(JSON.parse(m[2].content))}else if(m[0]==="EOSE"){clearTimeout(timer);ws.close();res(null)}}catch(_){clearTimeout(timer);res(null)}};ws.onerror=function(){clearTimeout(timer);res(null)}}catch(_){clearTimeout(timer);res(null)}})};var setStatus=function(el,msg,err){el.textContent=msg;el.className="auth-nostr-status"+(err?" auth-nostr-error":"")};var handleLogin=async function(url,relay,btn,st){btn.disabled=true;setStatus(st,"Looking for Nostr extension…");var nostr=await waitForExtension(3000);if(!nostr){setStatus(st,"No Nostr extension found. Install Alby or nos2x.",true);btn.disabled=false;return}setStatus(st,"Requesting public key…");var pk;try{pk=await nostr.getPublicKey()}catch(_){setStatus(st,"Extension denied access.",true);btn.disabled=false;return}setStatus(st,"Fetching your Nostr profile…");var meta=await fetchKind0(relay,pk,3000);setStatus(st,"Requesting login challenge…");var nonce,surl;try{var cr=await fetch(url+"?action=challenge");if(!cr.ok)throw new Error();var cd=await cr.json();nonce=cd.nonce;surl=cd.url}catch(_){setStatus(st,"Failed to get challenge. Reload and try again.",true);btn.disabled=false;return}setStatus(st,"Signing login request…");var ev;try{ev=await nostr.signEvent({kind:27235,created_at:Math.floor(Date.now()/1000),content:"",tags:[["u",surl],["method","POST"],["challenge",nonce]]})}catch(_){setStatus(st,"Signing was cancelled.",true);btn.disabled=false;return}setStatus(st,"Verifying with server…");var red;try{var vr=await fetch(url,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({event:ev,metadata:meta})});var vd=await vr.json();if(!vr.ok){setStatus(st,vd.error||"Login failed.",true);btn.disabled=false;return}red=vd.redirect}catch(_){setStatus(st,"Network error. Please try again.",true);btn.disabled=false;return}setStatus(st,"Logged in! Redirecting…");window.location.href=red};return{init:function(loginUrl,relay){var ready=function(fn){document.readyState!=="loading"?fn():document.addEventListener("DOMContentLoaded",fn)};ready(function(){var lb=document.getElementById("loginbtn");if(!lb)return;var form=lb.closest("form");if(!form)return;var w=document.createElement("div");w.className="auth-nostr-wrapper mt-3 text-center";w.innerHTML='<div class="auth-nostr-sep mb-2"><span class="auth-nostr-sep-text px-2">or</span></div><button type="button" id="auth-nostr-btn" class="btn btn-secondary w-100">⚡ Log in with Nostr</button><div id="auth-nostr-status" class="auth-nostr-status mt-2 small"></div>';form.parentNode.insertBefore(w,form.nextSibling);var btn=document.getElementById("auth-nostr-btn");var st=document.getElementById("auth-nostr-status");btn.addEventListener("click",function(){handleLogin(loginUrl,relay,btn,st)})})}}});
